  if(run.consumables.Count>0){GUI.Label(new Rect(x,rail.y+Us(4),Us(70),rail.height-Us(8)),"道具",new GUIStyle(body){fontSize=Fs(17),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleLeft});x+=Us(72);for(int i=0;i<run.consumables.Count;i++){int index=i;Rect r=new(x,rail.y+Us(5),rail.height-Us(10),rail.height-Us(10));if(DrawConsumableAt(r,run.consumables[i])){ConsumableSystem.Use(run,battle,index);if(battle.enemyHp<=0)WinBattle();return;}x+=r.width+Us(7);}}
  GUI.Label(new Rect(rail.center.x-Us(245),rail.y+Us(4),Us(490),rail.height-Us(8)),$"EN {run.energy}/3　　山札 {run.draw.Count}　　捨て札 {run.discard.Count}",new GUIStyle(body){fontSize=Fs(19),fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.94f,.85f,.65f)}});
  Rect endRect=new(rail.xMax-Us(246),rail.y+Us(7),Us(232),rail.height-Us(14));if(GUI.Button(endRect,"ターンを終了",new GUIStyle(button){fontSize=Fs(20),fontStyle=FontStyle.Bold})){if(BattleSystem.EndTurn(run,battle,dungeon.damage))FinishRun(false);}
 }
 void DrawCombatCardV2(Rect slot,CardInstance combatCard,bool affordable){int frameIndex=combatCard.type==CardType.Attack?0:combatCard.type==CardType.Skill?1:2;Texture2D frame=combatCardFrames!=null&&frameIndex<combatCardFrames.Length?combatCardFrames[frameIndex]:null;float frameAspect=frame!=null?frame.width/(float)frame.height:.67f;Rect rect=FitAspect(slot,frameAspect);var sourceItem=run.inventory.FirstOrDefault(x=>x.uid==combatCard.sourceItemUid);if(frame==null)GUI.Box(rect,GUIContent.none,bookEntrySelectedStyle);Rect illustration=new(rect.x+rect.width*.14f,rect.y+rect.height*.09f,rect.width*.72f,rect.height*.50f);GUI.Box(illustration,GUIContent.none,new GUIStyle(){normal={background=bookChipTex},border=new RectOffset(10,10,10,10)});GUI.color=affordable?Color.white:new Color(.43f,.43f,.40f,1);if(sourceItem!=null)DrawItemArt(FitAspect(illustration,1f),sourceItem.templateId);else DrawRoleArt(illustration,run.role);if(frame!=null)GUI.DrawTexture(rect,frame,ScaleMode.StretchToFill,true);GUI.color=Color.white;int titleSize=Fs(16),bodySize=Fs(14),footSize=Fs(12);Rect costRect=new(rect.x+rect.width*.015f,rect.y+rect.height*.015f,rect.width*.255f,rect.width*.255f);DrawFantasyText(costRect,combatCard.cost.ToString(),Fs(21),TextAnchor.MiddleCenter,Color.white);GUI.Label(new Rect(rect.x+rect.width*.12f,rect.y+rect.height*.62f,rect.width*.76f,rect.height*.085f),combatCard.name,new GUIStyle(header){alignment=TextAnchor.MiddleCenter,fontSize=titleSize,wordWrap=true,clipping=TextClipping.Clip,normal={textColor=new Color(.96f,.90f,.72f)}});GUI.Label(new Rect(rect.x+rect.width*.11f,rect.y+rect.height*.705f,rect.width*.78f,rect.height*.16f),combatCard.text,new GUIStyle(body){alignment=TextAnchor.UpperCenter,fontSize=bodySize,wordWrap=true,clipping=TextClipping.Clip,normal={textColor=new Color(.90f,.88f,.79f)}});string sourceName=combatCard.source;if(sourceItem!=null&&GameCatalog.Items.TryGetValue(sourceItem.templateId,out var itemDef))sourceName=itemDef.name;GUI.Label(new Rect(rect.x+rect.width*.095f,rect.y+rect.height*.875f,rect.width*.54f,rect.height*.07f),sourceName,new GUIStyle(header){alignment=TextAnchor.MiddleCenter,fontSize=footSize,clipping=TextClipping.Clip,normal={textColor=new Color(.92f,.73f,.35f)}});string durability=sourceItem!=null?$"耐久 {sourceItem.durability}/6":combatCard.roleCard?"役職":"基本";GUI.Label(new Rect(rect.x+rect.width*.64f,rect.y+rect.height*.875f,rect.width*.27f,rect.height*.07f),durability,new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=footSize,normal={textColor=sourceItem!=null&&sourceItem.durability<=1?new Color(1f,.42f,.32f):new Color(.82f,.79f,.66f)}});if(!affordable){Rect lockRect=new(rect.x+rect.width*.57f,rect.y+rect.height*.04f,rect.width*.31f,Us(27));GUI.Box(lockRect,GUIContent.none,new GUIStyle(){normal={background=battleStatusDebuffTex},border=new RectOffset(9,9,9,9)});GUI.Label(lockRect,"EN不足",new GUIStyle(body){alignment=TextAnchor.MiddleCenter,fontSize=Fs(12),fontStyle=FontStyle.Bold,normal={textColor=Color.white}});}}
 bool DrawConsumableAt(Rect slot,string id){bool hover=slot.Contains(UnityEngine.Event.current.mousePosition);GUI.Box(slot,GUIContent.none,hover?bookEntrySelectedStyle:bookEntryStyle);string visual=id=="heal"?"herb":id=="guard"?"buckler":id=="fire"?"bomb":"flask";DrawItemArt(new Rect(slot.x+5,slot.y+4,slot.width-10,slot.height-8),visual);if(hover){Rect tip=new(slot.center.x-62,slot.y-31,124,27);GUI.Box(tip,GUIContent.none,new GUIStyle(){normal={background=infoChipTex},border=new RectOffset(8,8,8,8)});GUI.Label(tip,ConsumableSystem.Name(id),new GUIStyle(body){fontSize=12,fontStyle=FontStyle.Bold,alignment=TextAnchor.MiddleCenter,normal={textColor=new Color(.96f,.87f,.66f)}});}return GUI.Button(slot,GUIContent.none,hotspot);}
